#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 13 (Layer 5): esclavo AXI4 full de registros.
#
# Subconjunto congelado: rafagas INCR y FIXED reales, WRAP tratada como INCR,
# AWLEN hasta 255, IDs propagados (AWID->BID, ARID->RID), WSTRB respetado,
# SLVERR en direccion no mapeada, AWLOCK ignorado.
#
# Mapa de registros (ventana de 64K en 0x80000000):
#   0x00 CTRL    W  bit0 start (autoclear), bit1 load_weights (autoclear)
#   0x04 STATUS  R  bit0 busy, bit1 done, bit2 error, bit7:4 clase
#   0x08 ID      R  0x4E505531
#   0x0C BASE    RW base del buffer en DDR, por defecto 0x70000000
#   0x10 ERRCODE R  ultimo RRESP/BRESP no OKAY
#
# Sondas: ID y BASE con RID/RLAST, WSTRB parcial, rafaga INCR de 4 con ID,
# SLVERR en lectura y escritura, rafaga FIXED sin avance de direccion.
#
# Requiere: ghdl 4.1.0 --std=08. Requiere los Pasos 1-12.
# Linea esperada al final:
# NPU PASO13 OK SONDAS SLAVE AXI 5/5 PASS
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
if [ ! -f "$DIR/rtl/npu_axi_pkg.vhd" ]; then
  echo "FALLO: falta rtl/npu_axi_pkg.vhd (corre primero el Paso 12)"; exit 1
fi
mkdir -p "$DIR/rtl" "$DIR/tb"
base64 -d << "EOF" > "$DIR/rtl/npu_axi_slave.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/tb_axi_slave.vhd"

EOF
base64 -d << "EOF" > "$DIR/run_axi_slave.sh"

EOF
chmod +x "$DIR/run_axi_slave.sh"
cd "$DIR"
bash run_axi_slave.sh
)
